function generateTrendData(baseValue: number): number[] {
  const data: number[] = [];
  let value = baseValue;
  for (let i = 0; i < 30; i++) {
    value += Math.random() * 20 - 8;
    if (value < 10) value = 10;
    data.push(Math.round(value));
  }
  return data;
}



